set-variable.value:
@{
      var jwt = (Jwt)context.Variables["jwt"];
      var oid = jwt.Claims.GetValueOrDefault("oid", "");
      var appid = jwt.Claims.GetValueOrDefault("appid", "");
      var azp = jwt.Claims.GetValueOrDefault("azp", "");
      return !String.IsNullOrEmpty(oid) ? oid : (!String.IsNullOrEmpty(appid) ? appid : azp);
    }

when.condition:
@{
        var jwt = (Jwt)context.Variables["jwt"];
        var oid = jwt.Claims.GetValueOrDefault("oid", "");
        var appid = jwt.Claims.GetValueOrDefault("appid", "");
        var azp = jwt.Claims.GetValueOrDefault("azp", "");
        return oid != "{{uiPrincipalId}}" && appid != "{{uiClientId}}" && azp != "{{uiClientId}}";
      }
